const PHASE_DEFS = [
  { id:0, label:"Not started",                   group:null },
  { id:1, label:"Screwpiles pending inspection", group:"sp" },
  { id:2, label:"Screwpiles approved",           group:"sp" },
  { id:3, label:"MS pending inspection",         group:"ms" },
  { id:4, label:"MS approved",                   group:"ms" },
  { id:5, label:"PV pending inspection",         group:"pv" },
  { id:6, label:"PV approved",                   group:"pv" },
];
const DEFAULT_COLORS = { sp:"#dc2626", ms:"#ea580c", pv:"#2563eb" };
function makePhases(cols) {
  const hex2rgb = h => [parseInt(h.slice(1,3),16),parseInt(h.slice(3,5),16),parseInt(h.slice(5,7),16)];
  const darken = (h,f) => { const [r,g,b]=hex2rgb(h); return `rgb(${Math.round(r*f)},${Math.round(g*f)},${Math.round(b*f)})`; };
  const lighten = (h,f) => { const [r,g,b]=hex2rgb(h); return `rgb(${Math.min(255,Math.round(r+(255-r)*f))},${Math.min(255,Math.round(g+(255-g)*f))},${Math.min(255,Math.round(b+(255-b)*f))})`; };
  return [
    { id:0, label:"Not started",                   color:"#1a1a2e", border:"#2d2d4a" },
    { id:1, label:"Screwpiles pending inspection", color:darken(cols.sp,0.45), border:lighten(cols.sp,0.2) },
    { id:2, label:"Screwpiles approved",           color:cols.sp,              border:lighten(cols.sp,0.5) },
    { id:3, label:"MS pending inspection",         color:darken(cols.ms,0.45), border:lighten(cols.ms,0.2) },
    { id:4, label:"MS approved",                   color:cols.ms,              border:lighten(cols.ms,0.5) },
    { id:5, label:"PV pending inspection",         color:darken(cols.pv,0.45), border:lighten(cols.pv,0.2) },
    { id:6, label:"PV approved",                   color:cols.pv,              border:lighten(cols.pv,0.5) },
  ];
}
