const EDIT_TOKEN = "S021Q6CJxYPVUfYz6tC1"; 
async function loadFromSheets() {
  const SUB_COLORS = ["#e53e3e","#dd6b20","#2b6cb0","#276749","#805ad5","#b7791f","#2c7a7b","#c53030"];
  const buildSubs = (rawSubs) => rawSubs.map((s, i) => ({
    id: s.id || s.name || `sub_${i}`,
    name: s.name,
    color: s.color || SUB_COLORS[i % SUB_COLORS.length],
    tables: s.tables || [],
    contractedMS: s.contractedMS || 0,
    contractedPV: s.contractedPV || 0,
    contracted: s.contractedMS||s.contractedPV ? Math.max(s.contractedMS||0,s.contractedPV||0) : (s.contracted || 0),
  }));
  try {
    const [dataRes, cfgRes] = await Promise.all([
      fetch(`${API_URL}?action=read`),
      fetch(`${API_URL}?action=readConfig`),
    ]);
    const dataJson = await dataRes.json();
    if (!dataJson.ok) throw new Error(dataJson.error);
    const phases = {};
    const subsMap = {};
    const pvMap = {};
    const msMap = {};
    dataJson.data.forEach(row => {
      phases[row.id] = parseInt(row.phase) || 0;
      if (row.subcontractor_ms) {
        if (!subsMap[row.subcontractor_ms]) subsMap[row.subcontractor_ms] = [];
        if (!subsMap[row.subcontractor_ms].includes(row.id)) subsMap[row.subcontractor_ms].push(row.id);
        msMap[row.id] = row.subcontractor_ms;
      }
      if (row.subcontractor_pv) {
        if (!subsMap[row.subcontractor_pv]) subsMap[row.subcontractor_pv] = [];
        if (!subsMap[row.subcontractor_pv].includes(row.id)) subsMap[row.subcontractor_pv].push(row.id);
        if (row.subcontractor_pv !== row.subcontractor_ms) pvMap[row.id] = row.subcontractor_pv;
      }
    });
    // Config: colors + full subs list (with contracted, color)
    let colors = null, subsFromConfig = null;
    try {
      const cfgJson = await cfgRes.json();
      if (cfgJson.ok && cfgJson.config) {
        colors = cfgJson.config.phaseColors || null;
        // Merge subsMap tables into config subs
        if (cfgJson.config.subs) {
          subsFromConfig = cfgJson.config.subs.map(s => {
            const key = Object.keys(subsMap).find(k => k.trim().toLowerCase() === (s.name||'').trim().toLowerCase());
            return { ...s, tables: (key ? subsMap[key] : subsMap[s.name] || subsMap[s.id]) || [] };
          });
        }
      }
    } catch(e) {}
    // Build final subs: prefer config (preserves order/color/contracted) else sheets map
    const finalSubs = subsFromConfig || buildSubs(Object.entries(subsMap).map(([name, tables]) => ({id:name,name,tables})));
    return { phases, subs: finalSubs, colors, subconPV: pvMap, subconMS: msMap, source: "sheets" };
  } catch(e) {
    return { phases: {...INITIAL_PHASES}, subs: INITIAL_SUBS.map((s,i)=>({...s,color:SUB_COLORS[i%SUB_COLORS.length]})), colors: null, subconPV: {}, subconMS: {}, source: "embedded" };
  }
}
async function pushToSheets(updates) {
  const now = new Date().toISOString().slice(0,10);
  const payload = updates.map(u => ({ ...u, last_updated: now, subcontractor_pv: u.subcontractor_pv ?? undefined }));
  const res = await fetch(API_URL, {
    method: "POST",
    headers: { "Content-Type": "text/plain" }, 
    body: JSON.stringify({ token: EDIT_TOKEN, updates: payload }),
  });
  const json = await res.json();
  if (!json.ok) throw new Error(json.error);
  return json.data;
}
async function pushConfig(config) {
  try {
    const res = await fetch(API_URL, {
      method: "POST",
      headers: { "Content-Type": "text/plain" },
      body: JSON.stringify({ token: EDIT_TOKEN, action: "writeConfig", config }),
    });
    const json = await res.json();
    return json.ok;
  } catch(e) { return false; }
}
function saveLocalConfig(subs, phaseColors) {
  try {
    localStorage.setItem('sp_subs_cfg', JSON.stringify(subs.map(s => ({ id: s.id, color: s.color }))));
    localStorage.setItem('sp_colors', JSON.stringify(phaseColors));
  } catch(e) {}
}
function loadLocalConfig() {
  try {
    const sc = localStorage.getItem('sp_subs_cfg');
    const c  = localStorage.getItem('sp_colors');
    return {
      subColors: sc ? JSON.parse(sc) : null,
      colors:    c  ? JSON.parse(c)  : null,
    };
  } catch(e) { return { subColors: null, colors: null }; }
}
